property_tests.invariant_check:
team = create_team()
state = 'active'
for op in random_lifecycle_ops:
  if op == 'archive':
    if state == 'active':
      resp = POST_archive(team.id)
      assert resp.status == 200
      state = 'archived'
    elif state == 'archived':
      resp = POST_archive(team.id)
      assert resp.status == 409
      assert parse_json(resp.body).message == 'team is already archived'
  elif op == 'reactivate':
    if state == 'archived':
      resp = POST_reactivate(team.id)
      assert resp.status == 200
      state = 'active'
    elif state == 'active':
      resp = POST_reactivate(team.id)
      assert resp.status == 409
  elif op == 'delete':
    if state == 'active':
      resp = DELETE_team(team.id)
      assert resp.status == 409
      assert parse_json(resp.body).message == 'team must be archived before deletion'
    elif state == 'archived':
      resp = DELETE_team(team.id)
      assert resp.status == 204
      state = 'deleted'
      break  // terminal state

// Normal deletion case
team_exists_before = query_scalar(db, 'SELECT count(*) FROM teams WHERE id = ?', team.id) == 1
members_count_before = query_scalar(db, 'SELECT count(*) FROM team_members WHERE team_id = ?', team.id)
resp = DELETE('/api/v1/teams/' + team.id, headers={Authorization: admin_token})
if resp.status == 204:
  assert query_scalar(db, 'SELECT count(*) FROM teams WHERE id = ?', team.id) == 0
  assert query_scalar(db, 'SELECT count(*) FROM team_members WHERE team_id = ?', team.id) == 0
else:
  // Any failure: both still present
  assert query_scalar(db, 'SELECT count(*) FROM teams WHERE id = ?', team.id) == 1
  assert query_scalar(db, 'SELECT count(*) FROM team_members WHERE team_id = ?', team.id) == members_count_before
